const pbiResp = $input.first().json;
const prev = $('DAX Generator').first().json;

// Verifica erros do DAX Generator
if (prev.daxError) {
  return [{ json: { ...prev, queryOk: false, queryError: prev.daxError, pbiRawResult: null } }, null];
}

// Verifica erro na resposta do Power BI
if (pbiResp.error || pbiResp.message) {
  return [{ json: { ...prev, queryOk: false, queryError: pbiResp.error?.message || pbiResp.message, pbiRawResult: pbiResp } }, null];
}

// Extrai as linhas do resultado
let rows = [];
try {
  rows = pbiResp.results?.[0]?.tables?.[0]?.rows || [];
} catch(e) {
  rows = [];
}

if (rows.length === 0) {
  return [null, { json: { ...prev, queryOk: false, queryError: 'Nenhum dado encontrado para esta consulta.', pbiRawResult: pbiResp } }];
}

return [{ json: { ...prev, queryOk: true, queryError: null, pbiRows: rows, pbiRowCount: rows.length, pbiRawResult: pbiResp } }, null];

